import static org.apache.commons.csv.Token.Type.*;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.Reader;
import java.lang.reflect.Field;
import java.util.LinkedHashMap;
import java.util.Map;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class CSVParserTest {

    private CSVParser csvParser;

    @BeforeEach
    void setUp() throws Exception {
        // Create a dummy CSVFormat mock or real instance as per constructor requirement
        CSVFormat format = mock(CSVFormat.class);

        // Use a Reader mock instead of null to avoid NullPointerException in constructor
        Reader reader = mock(Reader.class);

        // Create CSVParser instance via reflection to set final headerMap field
        csvParser = new CSVParser(reader, format);

        // Because headerMap is final and set in constructor, we need to override it via reflection in tests
    }

    @Test
    void testGetHeaderMapReturnsNullWhenHeaderMapIsNull() throws Exception {
        // Set headerMap field to null using reflection
        Field headerMapField = CSVParser.class.getDeclaredField("headerMap");
        headerMapField.setAccessible(true);

        // Remove final modifier to allow setting null
        Field modifiersField = Field.class.getDeclaredField("modifiers");
        modifiersField.setAccessible(true);
        modifiersField.setInt(headerMapField, headerMapField.getModifiers() & ~java.lang.reflect.Modifier.FINAL);

        headerMapField.set(csvParser, null);

        Map<String, Integer> result = csvParser.getHeaderMap();
        assertNull(result);
    }

    @Test
    void testGetHeaderMapReturnsCopyOfHeaderMap() throws Exception {
        // Prepare a LinkedHashMap as headerMap
        LinkedHashMap<String, Integer> originalHeaderMap = new LinkedHashMap<>();
        originalHeaderMap.put("A", 1);
        originalHeaderMap.put("B", 2);

        // Set headerMap field using reflection
        Field headerMapField = CSVParser.class.getDeclaredField("headerMap");
        headerMapField.setAccessible(true);

        // Remove final modifier to allow setting new map
        Field modifiersField = Field.class.getDeclaredField("modifiers");
        modifiersField.setAccessible(true);
        modifiersField.setInt(headerMapField, headerMapField.getModifiers() & ~java.lang.reflect.Modifier.FINAL);

        headerMapField.set(csvParser, originalHeaderMap);

        Map<String, Integer> returnedMap = csvParser.getHeaderMap();

        // Verify returned map is not null
        assertNotNull(returnedMap);

        // Verify returned map has same entries
        assertEquals(originalHeaderMap, returnedMap);

        // Verify returned map is a new instance (not the same reference)
        assertNotSame(originalHeaderMap, returnedMap);

        // Modifying returned map should not affect originalHeaderMap
        returnedMap.put("C", 3);
        assertFalse(originalHeaderMap.containsKey("C"));
    }
}
